function seedOrders() {
  localStorage.setItem('tienda_react_orders', JSON.stringify([
    {
      id: 'uuid-123',
      orderNumber: 'Ana-ABCDEF',
      createdAt: '2026-04-29T10:00:00.000Z',
      customerName: 'Ana García',
      totalItems: 1,
      subtotalPrice: 100,
      discountAmount: 0,
      couponCode: null,
      totalPrice: 100,
      items: [
        {
          id: 1,
          name: 'Auriculares',
          quantity: 1,
          price: 100,
          image: 'https://example.com/a.jpg',
        },
      ],
    },
  ]));
}

describe('Orders integration', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    localStorage.clear();
    seedOrders();
  });

  afterEach(() => {
    cleanup();
  });

  it('renders the visible order number in header', () => {
    render(<Orders />);

    expect(screen.getByText('Pedido Ana-ABCDEF')).toBeInTheDocument();
    expect(screen.getByRole('heading', { name: 'Mis pedidos' })).toBeInTheDocument();
  });

  it('filters orders by search input using debounced search', async () => {
    const user = userEvent.setup();
    render(<Orders />);

    const searchInput = screen.getByPlaceholderText('Buscar por ID o producto...');
    await user.type(searchInput, 'NO-EXISTE');

    await waitFor(() => {
      expect(screen.getByText('No hay resultados')).toBeInTheDocument();
    });

    await user.clear(searchInput);
    await user.type(searchInput, 'Ana-ABCDEF');

    await waitFor(() => {
      expect(screen.getByText('Pedido Ana-ABCDEF')).toBeInTheDocument();
    });
  });

  it('dispatches reorder action and shows success toast with orderNumber', async () => {
    const user = userEvent.setup();
    render(<Orders />);

    await user.click(screen.getByRole('button', { name: /Volver a pedir pedido/ }));

    expect(mockDispatch).toHaveBeenCalledWith({
      type: 'ADD_ORDER_ITEMS',
      payload: {
        items: [
          expect.objectContaining({
            id: 1,
            name: 'Auriculares',
            quantity: 1,
          }),
        ],
      },
    });

    expect(mockShowToast).toHaveBeenCalledWith(
      'Se añadieron productos del pedido Ana-ABCDEF',
      'success'
    );
  });

  it('supports keyboard search focus shortcut and toggles aria-expanded on details', async () => {
    const user = userEvent.setup();
    render(<Orders />);

    await user.keyboard('/');
    const searchInput = screen.getByPlaceholderText('Buscar por ID o producto...');
    expect(searchInput).toHaveFocus();

    const detailButton = screen.getByRole('button', { name: 'Ver detalle' });
    expect(detailButton).toHaveAttribute('aria-expanded', 'false');

    await user.click(detailButton);
    expect(screen.getByRole('button', { name: 'Ocultar detalle' })).toHaveAttribute('aria-expanded', 'true');
  });

  it('shows clear search button and clears the term with Escape', async () => {
    const user = userEvent.setup();
    render(<Orders />);

    const searchInput = screen.getByPlaceholderText('Buscar por ID o producto...');
    await user.type(searchInput, 'NO-EXISTE');

    const clearButton = screen.getByRole('button', { name: 'Limpiar búsqueda' });
    expect(clearButton).toBeInTheDocument();
    expect(searchInput).toHaveAttribute('aria-describedby', 'orders-search-shortcut');
    expect(screen.getByText('Atajos: / para buscar y Escape para limpiar.')).toBeInTheDocument();

    await user.keyboard('{Escape}');

    await waitFor(() => {
      expect(searchInput).toHaveValue('');
      expect(screen.queryByRole('button', { name: 'Limpiar búsqueda' })).not.toBeInTheDocument();
      expect(screen.getByText('Pedido Ana-ABCDEF')).toBeInTheDocument();
    });
  });
});
